import React, { useState } from 'react';
import axios from 'axios';

const Admin = () => {
  const [jobData, setJobData] = useState({
    title: '', loc: '', type: 'On-site', salary: ''
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:5000/api/admin/jobs', jobData);
      alert("Job Posted Successfully!");
      setJobData({ title: '', loc: '', type: 'On-site', salary: '' });
    } catch (err) {
      alert("Failed to post job");
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 pt-32 pb-20 px-6">
      <div className="max-w-3xl mx-auto bg-white rounded-[3rem] p-12 shadow-xl border border-gray-100">
        <h1 className="text-4xl font-black tracking-tighter mb-2 text-gray-950">Admin Panel</h1>
        <p className="text-orange-600 font-bold mb-10 uppercase tracking-widest text-xs">Post a New Career Opening</p>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-2">Job Title</label>
            <input required type="text" placeholder="e.g. Senior React Developer" className="w-full p-5 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-orange-500 font-bold"
              value={jobData.title} onChange={e => setJobData({...jobData, title: e.target.value})} />
          </div>

          <div className="grid md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-2">Location</label>
              <input required type="text" placeholder="e.g. Mumbai, India" className="w-full p-5 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-orange-500 font-bold"
                value={jobData.loc} onChange={e => setJobData({...jobData, loc: e.target.value})} />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-2">Job Type</label>
              <select className="w-full p-5 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-orange-500 font-bold"
                value={jobData.type} onChange={e => setJobData({...jobData, type: e.target.value})}>
                <option>On-site</option>
                <option>Remote</option>
                <option>Hybrid</option>
              </select>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-2">Salary Range</label>
            <input required type="text" placeholder="e.g. SAR 5,000 - 7,000" className="w-full p-5 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-orange-500 font-bold"
              value={jobData.salary} onChange={e => setJobData({...jobData, salary: e.target.value})} />
          </div>

          <button type="submit" className="w-full bg-gray-950 text-white py-6 rounded-2xl font-black text-lg hover:bg-orange-600 transition-all shadow-2xl shadow-gray-200 mt-4">
            Publish Job Posting
          </button>
        </form>
      </div>
    </div>
  );
};

export default Admin;
